#!/usr/bin/env node

/**
 * Sync changelog entries from CHANGELOG.md into src/changelog.ts.
 *
 * This runs as a prebuild step so that the TUI header always reflects
 * the latest release notes from the single source of truth (CHANGELOG.md).
 * The generated file is committed to the repo so that lint/typecheck work
 * without a build step.
 *
 * Usage: node scripts/sync-changelog.js
 */

import { readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const rootDir = join(__dirname, '..');

const changelog = readFileSync(join(rootDir, 'CHANGELOG.md'), 'utf-8');

/**
 * Parse CHANGELOG.md (Keep a Changelog format) into version entries.
 *
 * Extracts:
 *   - version from `## [x.y.z] - YYYY-MM-DD`
 *   - first non-empty paragraph after the heading as the summary
 *
 * Skips [Unreleased] sections.
 */
function parseChangelog(markdown) {
  const entries = [];
  const versionPattern = /^## \[(\d+\.\d+\.\d+)\] - (\d{4}-\d{2}-\d{2})/;

  const lines = markdown.split('\n');
  let i = 0;

  while (i < lines.length) {
    const match = versionPattern.exec(lines[i]);
    if (!match) {
      i++;
      continue;
    }

    const version = `v${match[1]}`;
    const date = match[2];
    i++;

    // Skip blank lines to find the first content paragraph
    while (i < lines.length && lines[i].trim() === '') {
      i++;
    }

    // Collect the first non-heading paragraph as the summary
    let summary = '';
    if (i < lines.length && !lines[i].startsWith('#')) {
      summary = lines[i].trim();
      i++;
    }

    if (summary === '') {
      summary = `Release ${version}`;
    }

    entries.push({ version, date, changes: summary });
  }

  return entries;
}

const entries = parseChangelog(changelog);

const entriesLiteral = entries
  .map(
    (e) =>
      `  {\n    version: '${e.version}',\n    date: '${e.date}',\n    changes: '${e.changes.replace(/\\/g, '\\\\').replace(/'/g, "\\'")}',\n  }`,
  )
  .join(',\n')
  .concat(entries.length > 0 ? ',' : '');

const content = `// Auto-generated by scripts/sync-changelog.js — do not edit manually.
// Source of truth: CHANGELOG.md

export interface ChangelogEntry {
  readonly version: string;
  readonly date: string;
  readonly changes: string;
}

export const CHANGELOG: readonly ChangelogEntry[] = [
${entriesLiteral}
];
`;

const targetPath = join(rootDir, 'src', 'changelog.ts');

// Only write if content changed to avoid unnecessary rebuilds.
try {
  const existing = readFileSync(targetPath, 'utf-8');
  if (existing === content) {
    process.exit(0);
  }
} catch (err) {
  if (err.code !== 'ENOENT') {
    throw err;
  }
}

writeFileSync(targetPath, content, 'utf-8');
console.log(`Synced ${entries.length} changelog entries → src/changelog.ts`);
